// A simple exception example
public class ExceptionDemo {
    public static void main(String[] args) {
        try {
            int result = 10 / 0;  // This throws ArithmeticException
            System.out.println(result);  // This line never executes
        } catch (ArithmeticException e) {
            System.out.println("Error: Cannot divide by zero!");
            System.out.println("Message: " + e.getMessage());
        }
        System.out.println("Program continues safely.");
    }
}
// Output:
// Error: Cannot divide by zero!
// Message: / by zero
// Program continues safely.

// The Exception Family Tree:
//
//          Throwable
//          /       \
//       Error    Exception
//    (serious)   /        \
//         RuntimeException  IOException
//         (unchecked)       FileNotFoundException
//         /       \         (all checked)
//  NullPointer  ArrayIndex
//  Exception    OutOfBounds
//               Exception

// Checked exception - MUST handle
try {
    FileReader file = new FileReader("data.txt");
} catch (FileNotFoundException e) {
    System.out.println("File not found!");
}

// Unchecked exception - SHOULD handle for security
String name = null;
try {
    int len = name.length();  // NullPointerException!
} catch (NullPointerException e) {
    System.out.println("Name was not set!");
}

// CHECKED: Compiler forces you to handle it
// Option 1: Catch it
public void readFile() {
    try {
        FileReader fr = new FileReader("secret.txt");
    } catch (FileNotFoundException e) {
        System.out.println("File not found");
    }
}

// Option 2: Declare it (pass responsibility to caller)
public void readFile() throws FileNotFoundException {
    FileReader fr = new FileReader("secret.txt");
}

// UNCHECKED: Compiler doesn't force handling
// But you SHOULD handle it for security!
public void processData(String input) {
    // DANGEROUS - no null check!
    int length = input.length(); // NullPointerException if input is null

    // SECURE - check first!
    if (input != null) {
        int length = input.length();
    } else {
        System.out.println("Input cannot be null");
    }
}

import java.io.*;

public class SafeFileReader {
    public static String readSecret(String filename) {
        BufferedReader reader = null;
        try {
            reader = new BufferedReader(new FileReader(filename));
            return reader.readLine();
        } catch (FileNotFoundException e) {
            // Specific exception first
            System.out.println("Error: File not found");
            return null;
        } catch (IOException e) {
            // More general exception second
            System.out.println("Error reading file");
            return null;
        } finally {
            // ALWAYS runs - cleanup!
            try {
                if (reader != null) {
                    reader.close();
                }
            } catch (IOException e) {
                // Log but don't expose
            }
        }
    }
}

// VULNERABLE CODE - Can bypass authentication!
boolean login(String user, String pwd) {
    boolean loggedIn = true;  // DANGER: starts as true!
    String realPwd = getPwdFromDb(user);
    try {
        // If pwd is null, NullPointerException thrown here!
        if (!MessageDigest.getInstance("SHA-256")
                .digest(pwd.getBytes()).equals(realPwd)) {
            loggedIn = false;
        }
    } catch (Exception e) {
        // This cannot happen, ignore  <-- FATAL MISTAKE!
    }
    return loggedIn;  // Returns TRUE if exception was thrown!
}

// ATTACK: login("admin", null) → NullPointerException
// → empty catch block → loggedIn still true → ACCESS GRANTED!

// SECURE CODE - Fail-safe default
boolean login(String user, String pwd) {
    boolean loggedIn = false;  // SAFE: starts as false!
    if (user == null || pwd == null) return false;  // Null check
    String realPwd = getPwdFromDb(user);
    try {
        if (MessageDigest.getInstance("SHA-256")
                .digest(pwd.getBytes()).equals(realPwd)) {
            loggedIn = true;  // Only true on success
        }
    } catch (Exception e) {
        loggedIn = false;  // Explicit fail-safe
    }
    return loggedIn;
}

// VULNERABLE - Leaks sensitive information!
void validatePwd(String user, String pwd) throws Exception {
    String realPwd = getPwdFromDb(user);
    if (realPwd == null)
        throw new Exception("user=" + user);  // Leaks username!
    if (!pwd.equals(realPwd))
        throw new Exception("user=" + user
            + " pwd=" + pwd           // Leaks password!!!
            + " expected=" + realPwd);  // Leaks real password!!!
}

// VULNERABLE caller - prints everything to user!
try {
    validatePwd(user, pwd);
} catch (Exception e) {
    System.out.println(e);       // Shows all internal details!
    e.printStackTrace();          // Shows full stack trace!
}

// SECURE - Generic message to user, details logged privately
try {
    validatePwd(user, pwd);
} catch (Exception e) {
    String logId = logError(e);  // Store details securely
    System.out.println("Login failed.");
    System.out.println("Contact support with ID: " + logId);
}

// VULNERABLE SERVER - One bad request crashes everything!
public void handleRequest(String input) {
    int value = Integer.parseInt(input);  // What if input = "abc"?
    // NumberFormatException → server crashes!
    processValue(value);
}

// SECURE SERVER - Graceful error handling
public void handleRequest(String input) {
    try {
        // Validate input first
        if (input == null || input.trim().isEmpty()) {
            sendError("Please provide a valid number");
            return;
        }
        int value = Integer.parseInt(input);
        processValue(value);
    } catch (NumberFormatException e) {
        // Handle specific error gracefully
        sendError("Invalid number format");
        logger.warn("Bad input received: " + sanitize(input));
    } catch (Exception e) {
        // Catch-all prevents server crash
        sendError("An error occurred. Please try again.");
        logger.error("Unexpected error", e);
    }
    // Server continues running for other users!
}

import java.util.logging.Logger;
import java.util.UUID;

public class SecureLogin {
    private static final Logger secureLog = 
        Logger.getLogger("SecureAudit");

    public boolean login(String user, String pwd) {
        try {
            validatePassword(user, pwd);
            return true;
        } catch (Exception e) {
            // Generate unpredictable reference ID
            String logId = UUID.randomUUID().toString()
                               .substring(0, 8);

            // Log full details to SECURE log only
            secureLog.severe("Login failure [" + logId + "]: "
                + e.getClass().getName() + " - " + e.getMessage());

            // Show GENERIC message to user with reference
            System.out.println("Login failed.");
            System.out.println("If the problem persists, "
                + "contact support with reference: " + logId);

            return false;  // Always fail securely
        }
    }
}

// VULNERABLE: CWE-395 - Using exception to detect null
public String getUserEmail(User user) {
    try {
        return user.getProfile().getEmail().toLowerCase();
    } catch (NullPointerException e) {
        // Which was null? user? getProfile()? getEmail()?
        // We have NO IDEA which part failed!
        return "unknown";
    }
}

// SECURE: Explicit null checks (defensive programming)
public String getUserEmail(User user) {
    if (user == null) {
        logger.warn("Null user passed to getUserEmail");
        return "unknown";
    }
    if (user.getProfile() == null) {
        logger.warn("User has no profile: " + user.getId());
        return "unknown";
    }
    String email = user.getProfile().getEmail();
    if (email == null) {
        return "unknown";
    }
    return email.toLowerCase();
}

// VULNERABLE: CWE-476 - No null checks
public void processOrder(Order order) {
    String customerName = order.getCustomer().getName();
    double total = order.getItems().stream()
        .mapToDouble(Item::getPrice).sum();
    System.out.println(customerName + " owes: $" + total);
}
// If order is null → NullPointerException (crash!)
// If getCustomer() returns null → NullPointerException!
// If getItems() returns null → NullPointerException!

// SECURE: Defensive null checking
public void processOrder(Order order) {
    if (order == null) {
        logger.error("Null order received");
        throw new IllegalArgumentException("Order cannot be null");
    }

    String customerName = "Unknown";
    if (order.getCustomer() != null && 
        order.getCustomer().getName() != null) {
        customerName = order.getCustomer().getName();
    }

    double total = 0.0;
    if (order.getItems() != null) {
        total = order.getItems().stream()
            .filter(item -> item != null)
            .mapToDouble(Item::getPrice).sum();
    }

    System.out.println(customerName + " owes: $" + total);
}

// A method following ALL 10 best practices:
public boolean secureTransfer(String fromAccount, 
        String toAccount, String amountStr) {
    // Practice 8: Validate inputs first
    if (fromAccount == null || toAccount == null || 
        amountStr == null) {
        logger.warn("Null input to transfer");
        return false;  // Practice 1: fail-safe default
    }

    Connection conn = null;
    try {
        double amount = Double.parseDouble(amountStr);
        if (amount <= 0) return false;  // Validate range

        conn = getConnection();
        // ... perform transfer logic ...
        return true;  // Only true on complete success

    } catch (NumberFormatException e) {
        // Practice 2: Specific exception first
        logger.warn("Invalid amount format");
        return false;
    } catch (SQLException e) {
        // Practice 6: Secure logging
        String refId = UUID.randomUUID().toString().substring(0,8);
        logger.severe("DB error [" + refId + "]: " + e.getMessage());
        System.out.println("Transfer failed. Ref: " + refId);
        return false;  // Practice 1: fail-safe
    } catch (Exception e) {
        // Practice 10: Catch-all for long-lived service
        logger.severe("Unexpected error: " + e.getClass());
        return false;
    } finally {
        // Practice 7: Always cleanup
        if (conn != null) {
            try { conn.close(); } catch (Exception e) { }
        }
    }
}

