// OWASP Principles in Action:

// 1. FAIL SECURELY - Default to deny
boolean isAuthorised = false;  // Default: no access
try {
    isAuthorised = checkPermission(user, resource);
} catch (Exception e) {
    // On ANY error, access remains denied
    logger.error("Permission check failed", e);
}

// 2. DEFENCE IN DEPTH - Multiple layers
try {  // Layer 1: Method level
    validateInput(data);
    try {  // Layer 2: Operation level
        result = processData(data);
    } catch (ProcessingException e) {
        handleProcessingError(e);
    }
} catch (ValidationException e) {
    handleValidationError(e);
} catch (Exception e) {  // Layer 3: Catch-all
    handleUnexpectedError(e);
}

// 3. LEAST PRIVILEGE for error messages
// User sees: "Access denied"
// Admin log sees: "User john attempted to access /admin/users "
//                 + "from IP 192.168.1.50 at 2024-03-15 14:22:01"

