public class BasicTryCatch {
    public static void main(String[] args) {
        System.out.println("Program starting...");

        // WITHOUT try-catch: program would crash here
        try {
            int numerator = 100;
            int denominator = 0;
            int result = numerator / denominator;
            System.out.println("Result: " + result);
        } catch (ArithmeticException e) {
            System.out.println("ERROR: Cannot divide by zero!");
            System.out.println("Exception type: " + e.getClass().getSimpleName());
            System.out.println("Message: " + e.getMessage());
        }

        // Program continues safely!
        System.out.println("Program continues running.");
        System.out.println("Other operations work fine.");
    }
}

public class MultipleCatch {
    public static void main(String[] args) {
        String[] data = {"42", "hello", null, "99"};

        for (int i = 0; i <= data.length; i++) {
            try {
                System.out.println("\nProcessing index " + i + "...");
                String value = data[i];
                int number = Integer.parseInt(value);
                System.out.println("Success! Number = " + number);

            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("ERROR: Index " + i + " is out of bounds!");
                System.out.println("Array only has " + data.length + " elements (0-" + (data.length-1) + ")");
            } catch (NumberFormatException e) {
                System.out.println("ERROR: '" + data[i] + "' is not a valid number!");
            } catch (NullPointerException e) {
                System.out.println("ERROR: Value at index " + i + " is null!");
            }
        }
        System.out.println("\nAll items processed safely.");
    }
}

public class FinallyDemo {
    public static void main(String[] args) {
        System.out.println("=== Test 1: No exception ===");
        processData(10, 2);

        System.out.println("\n=== Test 2: Exception occurs ===");
        processData(10, 0);

        System.out.println("\n=== Test 3: Null input ===");
        processWithString(null);
    }

    static void processData(int a, int b) {
        System.out.println("Opening resource...");
        try {
            System.out.println("Calculating " + a + " / " + b);
            int result = a / b;
            System.out.println("Result = " + result);
        } catch (ArithmeticException e) {
            System.out.println("CAUGHT: " + e.getMessage());
        } finally {
            System.out.println("FINALLY: Closing resource (always runs!)");
        }
    }

    static void processWithString(String text) {
        try {
            System.out.println("Length: " + text.length());
        } catch (NullPointerException e) {
            System.out.println("CAUGHT: Input was null!");
        } finally {
            System.out.println("FINALLY: Cleanup complete (always runs!)");
        }
    }
}

import java.security.MessageDigest;
import java.util.Arrays;

public class LoginBypassDemo {
    // Simulated password database
    static String getPasswordHash(String user) {
        if ("admin".equals(user)) return "hashed_admin_pwd";
        return null;
    }

    // VULNERABLE VERSION - Can be bypassed!
    static boolean vulnerableLogin(String user, String pwd) {
        boolean loggedIn = true;  // DANGER: default is TRUE!
        String realPwd = getPasswordHash(user);
        try {
            byte[] inputHash = MessageDigest.getInstance("SHA-256")
                                .digest(pwd.getBytes());  // NPE if pwd is null!
            if (!Arrays.equals(inputHash, realPwd.getBytes())) {
                loggedIn = false;
            }
        } catch (Exception e) {
            // "This cannot happen" - FAMOUS LAST WORDS!
        }
        return loggedIn;
    }

    // SECURE VERSION - Cannot be bypassed
    static boolean secureLogin(String user, String pwd) {
        boolean loggedIn = false;  // SAFE: default is FALSE!
        if (user == null || pwd == null) {
            System.out.println("  [LOG] Null input detected");
            return false;
        }
        String realPwd = getPasswordHash(user);
        try {
            byte[] inputHash = MessageDigest.getInstance("SHA-256")
                                .digest(pwd.getBytes());
            if (Arrays.equals(inputHash, realPwd.getBytes())) {
                loggedIn = true;
            }
        } catch (Exception e) {
            loggedIn = false;  // Explicit fail-safe
            System.out.println("  [SECURE LOG] Auth error: " + e.getClass().getSimpleName());
        }
        return loggedIn;
    }

    public static void main(String[] args) {
        System.out.println("=== VULNERABLE LOGIN ===");
        System.out.println("Normal login: " + vulnerableLogin("admin", "wrong"));
        System.out.println("ATTACK (null pwd): " + vulnerableLogin("admin", null));

        System.out.println("\n=== SECURE LOGIN ===");
        System.out.println("Normal login: " + secureLogin("admin", "wrong"));
        System.out.println("ATTACK (null pwd): " + secureLogin("admin", null));
    }
}

public class InfoLeakDemo {
    // Simulated database
    static String getPassword(String user) {
        if ("admin".equals(user)) return "SuperSecret123";
        return null;
    }

    // VULNERABLE - Leaks everything!
    static void vulnerableLogin(String user, String pwd) {
        System.out.println("--- VULNERABLE Error Output ---");
        try {
            String realPwd = getPassword(user);
            if (realPwd == null) {
                throw new Exception("User not found: " + user);
            }
            if (!pwd.equals(realPwd)) {
                throw new Exception(
                    "Wrong password for user=" + user
                    + " entered=" + pwd
                    + " expected=" + realPwd);  // LEAKS REAL PASSWORD!
            }
            System.out.println("Login successful!");
        } catch (Exception e) {
            // Prints EVERYTHING to the user!
            System.out.println("Error: " + e.getMessage());
            System.out.println("Stack trace:");
            e.printStackTrace(System.out);
        }
    }

    // SECURE - Generic message + secure log
    static void secureLogin(String user, String pwd) {
        System.out.println("--- SECURE Error Output ---");
        try {
            String realPwd = getPassword(user);
            if (realPwd == null || !pwd.equals(realPwd)) {
                // Don't distinguish between bad user and bad password!
                throw new SecurityException("Authentication failed");
            }
            System.out.println("Login successful!");
        } catch (Exception e) {
            String refId = "ERR-" + (int)(Math.random() * 90000 + 10000);
            // SECURE LOG (only admins see this)
            System.out.println("  [ADMIN LOG] " + refId + ": " + e.getMessage()
                + " user=" + user);
            // USER sees only this:
            System.out.println("Login failed. Username or password incorrect.");
            System.out.println("Contact support with reference: " + refId);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Attacker tries wrong password ===\n");
        vulnerableLogin("admin", "hacker123");
        System.out.println();
        secureLogin("admin", "hacker123");
    }
}

import java.io.FileReader;
import java.io.FileNotFoundException;

public class CheckedUncheckedDemo {

    // This method has a CHECKED exception
    // The compiler FORCES us to handle FileNotFoundException
    static void readCheckedFile() {
        try {
            FileReader fr = new FileReader("passwords.txt");
            System.out.println("File opened successfully");
            fr.close();
        } catch (FileNotFoundException e) {
            System.out.println("CHECKED: File not found - handled safely");
        } catch (Exception e) {
            System.out.println("CHECKED: Other error - " + e.getMessage());
        }
    }

    // This method has UNCHECKED exceptions
    // The compiler does NOT force us to handle them!
    static void riskyCalculation(String numberStr) {
        // These can all throw unchecked exceptions:
        int number = Integer.parseInt(numberStr);  // NumberFormatException
        int result = 100 / number;                  // ArithmeticException
        int[] arr = new int[number];
        arr[number] = result;                       // ArrayIndexOutOfBounds
        System.out.println("Result: " + result);
    }

    // SECURE version - handles unchecked exceptions too
    static void safeCalculation(String numberStr) {
        try {
            if (numberStr == null) {
                System.out.println("SAFE: Input cannot be null");
                return;
            }
            int number = Integer.parseInt(numberStr);
            if (number == 0) {
                System.out.println("SAFE: Cannot divide by zero");
                return;
            }
            int result = 100 / number;
            System.out.println("SAFE Result: " + result);
        } catch (NumberFormatException e) {
            System.out.println("SAFE: '" + numberStr + "' is not a number");
        } catch (Exception e) {
            System.out.println("SAFE: Unexpected error handled");
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Checked Exception ===");
        readCheckedFile();

        System.out.println("\n=== Unchecked - DANGEROUS ===");
        try {
            riskyCalculation("abc");
        } catch (Exception e) {
            System.out.println("CRASHED: " + e.getClass().getSimpleName());
        }

        System.out.println("\n=== Unchecked - SAFE ===");
        safeCalculation("abc");
        safeCalculation("0");
        safeCalculation(null);
        safeCalculation("5");
    }
}

public class DoSDemo {

    // VULNERABLE SERVER - crashes on bad input
    static class VulnerableServer {
        static void handleRequest(String input) {
            int userId = Integer.parseInt(input);  // No protection!
            System.out.println("Processing user #" + userId);
            // ... do work ...
        }
    }

    // SECURE SERVER - handles all inputs gracefully
    static class SecureServer {
        static void handleRequest(String input) {
            try {
                // Input validation FIRST
                if (input == null || input.trim().isEmpty()) {
                    System.out.println("[400] Bad request: empty input");
                    return;
                }

                int userId = Integer.parseInt(input.trim());

                if (userId < 0 || userId > 999999) {
                    System.out.println("[400] Bad request: ID out of range");
                    return;
                }

                System.out.println("[200] Processing user #" + userId);

            } catch (NumberFormatException e) {
                System.out.println("[400] Bad request: not a number");
            } catch (Exception e) {
                // Catch-all prevents crash
                System.out.println("[500] Internal error - logged for review");
            }
            // Server ALWAYS continues running!
        }
    }

    public static void main(String[] args) {
        String[] attacks = {"42", "abc", "", null, "99999999999", "-1", "5"};

        System.out.println("=== SECURE SERVER handles everything ===");
        for (String input : attacks) {
            System.out.print("Input '" + input + "': ");
            SecureServer.handleRequest(input);
        }

        System.out.println("\n=== VULNERABLE SERVER crashes ===");
        for (String input : attacks) {
            try {
                System.out.print("Input '" + input + "': ");
                VulnerableServer.handleRequest(input);
            } catch (Exception e) {
                System.out.println("SERVER CRASHED: " + e.getClass().getSimpleName());
            }
        }
    }
}

import java.util.UUID;
import java.util.ArrayList;
import java.util.List;

public class SecureLoggingDemo {
    // Simulated secure log storage (admin-only access)
    static List<String> secureLog = new ArrayList<>();

    static String logError(String context, Exception e) {
        // Generate unpredictable reference ID
        String refId = UUID.randomUUID().toString().substring(0, 8);

        // Store full details in secure log
        String logEntry = "[" + refId + "] " + context
            + " | Exception: " + e.getClass().getName()
            + " | Message: " + e.getMessage()
            + " | Time: " + java.time.LocalDateTime.now();
        secureLog.add(logEntry);

        return refId;  // Return only the reference ID
    }

    static void processPayment(String cardNumber, double amount) {
        try {
            if (cardNumber == null || cardNumber.length() < 16) {
                throw new IllegalArgumentException("Invalid card: " + cardNumber);
            }
            if (amount <= 0 || amount > 10000) {
                throw new IllegalArgumentException("Invalid amount: " + amount);
            }

            // Simulate processing
            if (amount > 5000) {
                throw new RuntimeException("Payment gateway timeout for card ending " 
                    + cardNumber.substring(12));
            }

            System.out.println("Payment of $" + amount + " processed.");

        } catch (Exception e) {
            // User sees ONLY this:
            String refId = logError("Payment processing", e);
            System.out.println("Payment could not be processed.");
            System.out.println("Please try again or contact support.");
            System.out.println("Reference: " + refId);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== User Experience ===");
        processPayment("4111111111111111", 50.00);
        System.out.println();
        processPayment(null, 100.00);
        System.out.println();
        processPayment("4111111111111111", 7500.00);

        System.out.println("\n=== Admin Log (restricted access) ===");
        for (String entry : secureLog) {
            System.out.println(entry);
        }
    }
}

public class CWE395Demo {

    // Simulated user profile system
    static String[] userNames = {"Alice", null, "Charlie"};
    static String[] userEmails = {"alice@mail.com", "bob@mail.com", null};

    // VULNERABLE: CWE-395 - Using NPE catch to detect null
    static String getInfoVulnerable(int userId) {
        try {
            String name = userNames[userId];
            String email = userEmails[userId];
            return name.toUpperCase() + " <" + email.toLowerCase() + ">";
        } catch (NullPointerException e) {
            // PROBLEM: Which was null? name? email? Both?
            // We don't know! Can't give specific error.
            return "Unknown user";
        } catch (ArrayIndexOutOfBoundsException e) {
            return "Invalid user ID";
        }
    }

    // SECURE: Explicit null checks
    static String getInfoSecure(int userId) {
        // Validate ID range first
        if (userId < 0 || userId >= userNames.length) {
            System.out.println("  [LOG] Invalid userId: " + userId);
            return "Invalid user ID";
        }

        String name = userNames[userId];
        String email = userEmails[userId];

        // Check each value individually
        if (name == null) {
            System.out.println("  [LOG] Missing name for userId: " + userId);
            name = "Unknown";
        }
        if (email == null) {
            System.out.println("  [LOG] Missing email for userId: " + userId);
            email = "no-email";
        }

