        }

        System.out.println("\n=== SECURE (Explicit Checks) ===");
        for (int i = 0; i <= 3; i++) {
            System.out.println("User " + i + ": " + getInfoSecure(i));
        }
    }
}

import java.util.Random;

public class LongLivedServiceDemo {
    static Random random = new Random();

    // Simulates a request that might fail in various ways
    static String processRequest(int requestId) throws Exception {
        int scenario = random.nextInt(5);
        switch (scenario) {
            case 0: return "OK: Request " + requestId + " processed";
            case 1: throw new IllegalArgumentException("Bad parameter");
            case 2: throw new NullPointerException("Null reference");
            case 3: throw new RuntimeException("Unexpected error");
            case 4: return "OK: Request " + requestId + " completed";
            default: return "OK";
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Long-Lived Service Starting ===");
        System.out.println("Processing 10 requests...\n");

        int successCount = 0;
        int errorCount = 0;

        for (int i = 1; i <= 10; i++) {
            try {
                // Layer 1: Try to process the request
                String result = processRequest(i);
                System.out.println("Request " + i + ": " + result);
                successCount++;

            } catch (IllegalArgumentException e) {
                // Layer 2: Known, specific errors
                System.out.println("Request " + i + ": [400] " + e.getMessage());
                errorCount++;

            } catch (Exception e) {
                // Layer 3: CATCH-ALL for unexpected errors
                // This prevents the service from crashing!
                System.out.println("Request " + i + ": [500] Internal error"
                    + " (" + e.getClass().getSimpleName() + ")");
                errorCount++;

                // In a real service, you would also:
                // - Log the full stack trace to secure log
                // - Alert the operations team
                // - Consider circuit breaker pattern
            }
            // Service ALWAYS continues to next request!
        }

        System.out.println("\n=== Service Status ===");
        System.out.println("Processed: " + (successCount + errorCount));
        System.out.println("Success: " + successCount);
        System.out.println("Errors: " + errorCount);
        System.out.println("Service still running!");
    }
}

public class SecurityExceptions {

    // Custom exception for authentication failures
    static class AuthenticationException extends Exception {
        private String attemptedUser;
        private String reason;

        public AuthenticationException(String user, String reason) {
            super("Authentication failed");
            this.attemptedUser = user;
            this.reason = reason;
        }

        // Only accessible to logging system, not public!
        String getAuditInfo() {
            return "User: " + attemptedUser + " Reason: " + reason;
        }
    }

    // Custom exception for authorisation failures
    static class AuthorisationException extends Exception {
        private String user;
        private String resource;

        public AuthorisationException(String user, String resource) {
            super("Access denied");
            this.user = user;
            this.resource = resource;
        }

        String getAuditInfo() {
            return "User: " + user + " tried to access: " + resource;
        }
    }

    // Custom exception for rate limiting
    static class RateLimitException extends Exception {
        private int attempts;
        public RateLimitException(int attempts) {
            super("Too many attempts");
            this.attempts = attempts;
        }
    }

    // Login system using custom exceptions
    static int loginAttempts = 0;

    static void login(String user, String pwd) 
            throws AuthenticationException, RateLimitException {
        loginAttempts++;
        if (loginAttempts > 3) {
            throw new RateLimitException(loginAttempts);
        }
        if (user == null || user.isEmpty()) {
            throw new AuthenticationException(user, "empty username");
        }
        if (!"admin".equals(user)) {
            throw new AuthenticationException(user, "user not found");
        }
        if (!"secret123".equals(pwd)) {
            throw new AuthenticationException(user, "wrong password");
        }
        System.out.println("Welcome, " + user + "!");
    }

    static void accessResource(String user, String resource)
            throws AuthorisationException {
        if (resource.startsWith("/admin") && !"admin".equals(user)) {
            throw new AuthorisationException(user, resource);
        }
        System.out.println(user + " accessed " + resource);
    }

    public static void main(String[] args) {
        String[][] tests = {
            {"admin", "secret123"},
            {"hacker", "password"},
            {"", "test"},
            {"admin", "wrong"},
            {"admin", "secret123"}  // 5th attempt
        };

        for (String[] test : tests) {
            try {
                login(test[0], test[1]);
                accessResource(test[0], "/admin/users");
            } catch (AuthenticationException e) {
                // User sees generic message
                System.out.println("Login failed.");
                // Admin sees detailed audit info
                System.out.println("  [AUDIT] " + e.getAuditInfo());
            } catch (AuthorisationException e) {
                System.out.println("Access denied.");
                System.out.println("  [AUDIT] " + e.getAuditInfo());
            } catch (RateLimitException e) {
                System.out.println("Account locked. Try again later.");
                System.out.println("  [AUDIT] Rate limit hit");
            }
        }
    }
}

import java.io.*;

public class TryWithResourcesDemo {

    // OLD WAY - verbose and error-prone
    static String readFileOldWay(String filename) {
        BufferedReader reader = null;
        try {
            reader = new BufferedReader(new FileReader(filename));
            StringBuilder content = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                content.append(line).append("\n");
            }
            return content.toString();
        } catch (FileNotFoundException e) {
            System.out.println("File not found: " + filename);
            return null;
        } catch (IOException e) {
            System.out.println("Error reading file");
            return null;
        } finally {
            // Must manually close - and handle close() exceptions!
            if (reader != null) {
                try {
                    reader.close();
                } catch (IOException e) {
                    // Even closing can throw!
                    System.out.println("Error closing file");
                }
            }
        }
    }

    // NEW WAY - clean and automatic
    static String readFileNewWay(String filename) {
        // Resource declared in parentheses - auto-closed!
        try (BufferedReader reader = 
                new BufferedReader(new FileReader(filename))) {
            StringBuilder content = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                content.append(line).append("\n");
            }
            return content.toString();
        } catch (FileNotFoundException e) {
            System.out.println("File not found: " + filename);
            return null;
        } catch (IOException e) {
            System.out.println("Error reading file");
            return null;
        }
        // reader.close() called AUTOMATICALLY!
    }

    // Multiple resources - all auto-closed
    static void copyFile(String source, String dest) {
        try (BufferedReader reader = new BufferedReader(new FileReader(source));
             BufferedWriter writer = new BufferedWriter(new FileWriter(dest))) {

            String line;
            while ((line = reader.readLine()) != null) {
                writer.write(line);
                writer.newLine();
            }
            System.out.println("File copied successfully");

        } catch (IOException e) {
            System.out.println("Copy failed: " + e.getMessage());
        }
        // BOTH reader AND writer auto-closed!
    }

    public static void main(String[] args) {
        // Create a test file
        try (FileWriter fw = new FileWriter("test.txt")) {
            fw.write("Hello, secure world!\n");
            fw.write("Exception handling matters!\n");
        } catch (IOException e) {
            System.out.println("Cannot create test file");
        }

        System.out.println("=== Old Way ===");
        String content1 = readFileOldWay("test.txt");
        System.out.println(content1);

        System.out.println("=== New Way (try-with-resources) ===");
        String content2 = readFileNewWay("test.txt");
        System.out.println(content2);

        System.out.println("=== Nonexistent file ===");
        readFileNewWay("nonexistent.txt");
    }
}

import java.io.*;

public class ThrowsDemo {

    // Method DECLARES it might throw FileNotFoundException
    // The caller MUST handle it
    static String readSecret(String filename) throws FileNotFoundException {
        FileReader fr = new FileReader(filename);
        // If we get here, file exists
        System.out.println("Reading from: " + filename);
        return "secret_data_here";
    }

    // Method DECLARES multiple possible exceptions
    static void processFile(String filename) 
            throws FileNotFoundException, IOException {
        FileReader fr = new FileReader(filename);
        BufferedReader br = new BufferedReader(fr);
        String line = br.readLine();
        if (line == null) {
            throw new IOException("File is empty!");
        }
        System.out.println("First line: " + line);
        br.close();
    }

    // This method HANDLES the exceptions
    static void safeRead(String filename) {
        try {
            String data = readSecret(filename);
            System.out.println("Got: " + data);
        } catch (FileNotFoundException e) {
            System.out.println("Cannot read secrets - file missing");
        }
    }

    // This method PASSES ALONG the exception
    static void riskyRead(String filename) throws FileNotFoundException {
        String data = readSecret(filename);  // Pass to our caller
        System.out.println("Got: " + data);
    }

    public static void main(String[] args) {
        System.out.println("=== safeRead handles it ===");
        safeRead("secrets.txt");
        safeRead("nonexistent.txt");

        System.out.println("\n=== riskyRead passes it up ===");
        try {
            riskyRead("nonexistent.txt");
        } catch (FileNotFoundException e) {
            System.out.println("main() caught it: " + e.getMessage());
        }
    }
}

import java.util.*;

public class SecureBankSystem {
    // Simulated accounts
    static Map<String, Double> accounts = new HashMap<>();
    static List<String> auditLog = new ArrayList<>();

    static {
        accounts.put("ACC001", 1000.00);
        accounts.put("ACC002", 500.00);
        accounts.put("ACC003", 2500.00);
    }

    // Custom exceptions
    static class InsufficientFundsException extends Exception {
        InsufficientFundsException(String acc, double has, double needs) {
            super("Insufficient funds");
            // Details only in audit log
        }
    }

    static class AccountNotFoundException extends Exception {
        AccountNotFoundException(String acc) {
            super("Account not found");
        }
    }

    // Secure transfer with complete exception handling
    static boolean transfer(String fromAcc, String toAcc, String amountStr) {
        String refId = UUID.randomUUID().toString().substring(0, 8);

        // 1. INPUT VALIDATION (prevent exceptions before they happen)
        if (fromAcc == null || toAcc == null || amountStr == null) {
            auditLog.add("[" + refId + "] REJECTED: null input");
            System.out.println("Transfer failed. Ref: " + refId);
            return false;
        }

        try {
            // 2. PARSE AND VALIDATE AMOUNT
            double amount = Double.parseDouble(amountStr);

            if (amount <= 0) {
                auditLog.add("[" + refId + "] REJECTED: negative amount " + amount);
                System.out.println("Invalid amount. Ref: " + refId);
                return false;
            }

            if (amount > 10000) {
                auditLog.add("[" + refId + "] REJECTED: exceeds limit " + amount);
                System.out.println("Amount exceeds transfer limit. Ref: " + refId);
                return false;
            }

            // 3. CHECK ACCOUNTS EXIST
            if (!accounts.containsKey(fromAcc)) {
                throw new AccountNotFoundException(fromAcc);
            }
            if (!accounts.containsKey(toAcc)) {
                throw new AccountNotFoundException(toAcc);
            }

            // 4. CHECK SUFFICIENT FUNDS
            double balance = accounts.get(fromAcc);
            if (balance < amount) {
                throw new InsufficientFundsException(fromAcc, balance, amount);
            }

            // 5. PERFORM TRANSFER
            accounts.put(fromAcc, accounts.get(fromAcc) - amount);
            accounts.put(toAcc, accounts.get(toAcc) + amount);

            auditLog.add("[" + refId + "] SUCCESS: " + fromAcc + " -> " + toAcc + " $" + amount);
            System.out.println("Transfer of $" + String.format("%.2f", amount) + " completed. Ref: " + refId);
            return true;

        } catch (NumberFormatException e) {
            auditLog.add("[" + refId + "] REJECTED: invalid amount format '" + amountStr + "'");
            System.out.println("Invalid amount format. Ref: " + refId);
            return false;
        } catch (AccountNotFoundException e) {
            auditLog.add("[" + refId + "] REJECTED: " + e.getMessage());
            System.out.println("Transfer failed - account error. Ref: " + refId);
            return false;
        } catch (InsufficientFundsException e) {
            auditLog.add("[" + refId + "] REJECTED: " + e.getMessage());
            System.out.println("Insufficient funds. Ref: " + refId);
            return false;
        } catch (Exception e) {
            // CATCH-ALL safety net
            auditLog.add("[" + refId + "] ERROR: " + e.getClass().getName() + " - " + e.getMessage());
            System.out.println("An error occurred. Ref: " + refId);
            return false;
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Secure Bank Transfers ===");
        System.out.println("Starting balances: " + accounts + "\n");

        transfer("ACC001", "ACC002", "200");     // Valid
        transfer("ACC001", "ACC002", "abc");     // Bad amount
        transfer("ACC001", "ACC999", "100");     // Bad account
        transfer("ACC002", "ACC001", "9999");    // Insufficient
        transfer(null, "ACC001", "100");          // Null input
        transfer("ACC003", "ACC001", "500");     // Valid

        System.out.println("\nFinal balances: " + accounts);

        System.out.println("\n=== AUDIT LOG (Admin Only) ===");
        for (String entry : auditLog) {
            System.out.println(entry);
        }
    }
}

