        try { queryVulnerable("SELECT * FROM users"); } catch(Exception e) {}
        try { queryVulnerable("DROP TABLE users"); } catch(Exception e) {}
        System.out.println("Vulnerable - Open connections: " + openConnections);

        openConnections = 0;
        querySecure("SELECT * FROM users");
