static boolean transfer(String from, String to, double amount) {
    if (!accounts.containsKey(from) || !accounts.containsKey(to)) return false;
    double origFrom = accounts.get(from);
    double origTo = accounts.get(to);
    try {
        if (origFrom < amount) return false;
        accounts.put(from, origFrom - amount);
        accounts.put(to, origTo + amount);
        return true;
    } catch (Exception e) {
        accounts.put(from, origFrom);
        accounts.put(to, origTo);
        return false;
    }
}

