    if (!pwd.matches(".*[a-z].*")) issues.add("Missing lowercase");
    if (!pwd.matches(".*\\d.*")) issues.add("Missing digit");
    if (!pwd.matches(".*[!@#$%^&*].*")) issues.add("Missing special character");
    return issues;
}

