public class ThreadSafety {
    // TODO: Run tasks in threads, handle exceptions in each
    // Main program should continue even if threads throw exceptions
    static void runTask(String name, Runnable task) {
        Thread t = new Thread(() -> {
            try {
                task.run();
            } catch (Exception e) {
                System.out.println("[Thread " + name + "] Error: " + e.getClass().getSimpleName());
            }
        });
        t.start();
        try { t.join(); } catch (InterruptedException e) { }
    }

    public static void main(String[] args) {
        runTask("A", () -> System.out.println("Task A: OK"));
        runTask("B", () -> { throw new RuntimeException("Boom!"); });
        runTask("C", () -> { String s = null; s.length(); });
        runTask("D", () -> System.out.println("Task D: OK"));
        System.out.println("Main: All tasks processed");
    }
}

