hints.message:
static List<String> scan(String code) {
    List<String> issues = new ArrayList<>();
    if (code.matches("(?s).*catch\\s*\\([^)]*\\)\\s*\\{\\s*\\}.*")) issues.add("EMPTY_CATCH");
    if (code.contains("printStackTrace")) issues.add("INFO_LEAK_STACKTRACE");
    if (code.contains("= true") && code.contains("try")) issues.add("UNSAFE_DEFAULT");
    if (code.contains("catch (NullPointerException")) issues.add("CWE-395");
    return issues;
}

