hints.message:
static String handleLoginRequest(String username, String password) {
    String ref = "REF-" + (int)(Math.random()*90000+10000);
    try {
        if (username == null || password == null || username.isEmpty() || password.isEmpty()) {
            auditLog.add("[" + ref + "] 400 - null/empty input");
            return "[400] Invalid request. Ref: " + ref;
        }
        if (failedLogins.getOrDefault(username, 0) >= MAX_FAILS) {
            auditLog.add("[" + ref + "] 429 - locked: " + username);
            return "[429] Account temporarily locked. Ref: " + ref;
        }
        String realPwd = users.get(username);
        if (realPwd != null && realPwd.equals(password)) {
            failedLogins.put(username, 0);
            auditLog.add("[" + ref + "] 200 - login: " + username);
            return "[200] Welcome, " + username;
        }
        failedLogins.merge(username, 1, Integer::sum);
        auditLog.add("[" + ref + "] 401 - failed: " + username);
        return "[401] Invalid username or password. Ref: " + ref;
    } catch (Exception e) {
        auditLog.add("[" + ref + "] 500 - " + e.getClass().getSimpleName());
        return "[500] An error occurred. Ref: " + ref;
    }
}
